algorithm:
My new algorithm uses greedy best-fit insertion with fallback to empty-assign creation, evaluating all existing assigns plus one potential new assign per order using a weighted score of travel distance increase and time feasibility, always attempting insertion into every viable assign before choosing the best improvement.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx        int
		costChange float64
		feasible   bool
	}
	for jj := range oris {
		bestCand := candidate{-1, 1e30, false}
		for ii := 0; ii <= dispatch.AssignsLen; ii++ {
			if ii == MAXASSIGNS {
				break
			}
			testAssign := dispatch.Assigns[ii]
			ok := testAssign.AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				testAssign.GenRoute()
				if testAssign.Cost >= 0 {
					baseCost := float64(0)
					if ii < dispatch.AssignsLen && dispatch.Assigns[ii].Cost >= 0 {
						baseCost = dispatch.Assigns[ii].Cost
					}
					delta := testAssign.Cost - baseCost
					score := delta
					if ii >= dispatch.AssignsLen {
						score += 10000
					}
					if !bestCand.feasible || score < bestCand.costChange {
						bestCand.idx = ii
						bestCand.costChange = score
						bestCand.feasible = true
					}
				}
				testAssign.RemoveShip(total_ship + jj)
				testAssign.GenRoute()
			}
		}
		insertIdx := bestCand.idx
		if insertIdx < 0 {
			insertIdx = dispatch.AssignsLen
			if insertIdx >= MAXASSIGNS {
				continue
			}
			dispatch.Assigns[insertIdx] = Assign{}
			dispatch.AssignsLen++
		}
		added := dispatch.Assigns[insertIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
		if added {
			dispatch.Assigns[insertIdx].GenRoute()
			if dispatch.Assigns[insertIdx].Cost < 0 {
				dispatch.Assigns[insertIdx].RemoveShip(total_ship + jj)
				dispatch.Assigns[insertIdx].GenRoute()
				if insertIdx == dispatch.AssignsLen-1 && dispatch.Assigns[insertIdx].StationsLen == 0 {
					dispatch.AssignsLen--
				}
			}
		} else if insertIdx >= dispatch.AssignsLen-1 && dispatch.Assigns[insertIdx].StationsLen == 0 {
			if dispatch.AssignsLen > 0 {
				dispatch.AssignsLen--
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

